        public static string Render(string tokenJson)
        {
            var compressed = Convert.FromBase64String(string.Concat(CompressedBase64Chunks));
            using var input = new MemoryStream(compressed);
            using var gzip = new GZipStream(input, CompressionMode.Decompress);
            using var reader = new StreamReader(gzip, Encoding.UTF8);
            return reader.ReadToEnd().Replace(TokenPlaceholder, tokenJson, StringComparison.Ordinal);
        }
